mapper.select:
SELECT COALESCE(MAX(global_seq), 0)
FROM im_offline_events_content
WHERE user_id = #{userId}

mapper.update:
UPDATE im_offline_events_delivery
SET
    last_sync_seq = #{lastSyncSeq},
    last_sync_time = #{lastSyncTime},
    delivery_status = #{deliveryStatus},
    delivery_count = delivery_count + 1,
    last_delivery_time = #{lastDeliveryTime},
    update_time = #{updateTime}
WHERE user_id = #{userId}
  AND device_id = #{deviceId}

UPDATE im_offline_events_delivery
last_sync_seq = #{lastSyncSeq}, last_sync_time = #{lastSyncTime}, delivery_status = #{deliveryStatus}, last_delivery_time = #{lastDeliveryTime}, delivery_count = delivery_count + 1, update_time = #{updateTime}
WHERE id = #{id}

mapper.delete:
DELETE FROM im_offline_events_content
WHERE expire_time IS NOT NULL
  AND expire_time <= #{expireTime}
    LIMIT #{batchSize}

update.foreach:
UPDATE im_offline_events_delivery
SET
last_sync_seq = #{record.lastSyncSeq},
last_sync_time = #{record.lastSyncTime},
delivery_status = #{record.deliveryStatus},
delivery_count = delivery_count + 1,
last_delivery_time = #{record.lastDeliveryTime},
update_time = #{record.updateTime}
WHERE user_id = #{record.userId}
AND device_id = #{record.deviceId}

mapper.select:
SELECT user_id as userId, COALESCE(MAX(global_seq), 0) as maxSequence FROM im_offline_events_content WHERE user_id IN
#{userId}
GROUP BY user_id
